const LEVELS = [
  { gridSize: 3, symbolCount: 3, flashSeconds: 5 },
  { gridSize: 3, symbolCount: 4, flashSeconds: 5 },
  { gridSize: 4, symbolCount: 5, flashSeconds: 5 },
  { gridSize: 4, symbolCount: 6, flashSeconds: 4 },
  { gridSize: 5, symbolCount: 7, flashSeconds: 4 },
  { gridSize: 5, symbolCount: 8, flashSeconds: 4 },
  { gridSize: 6, symbolCount: 10, flashSeconds: 3 }
];

export function getLevelConfig(level) {
  if (level <= LEVELS.length) {
    return LEVELS[level - 1];
  }
  const last = LEVELS[LEVELS.length - 1];
  return {
    gridSize: last.gridSize + Math.floor((level - LEVELS.length) / 2),
    symbolCount: last.symbolCount + (level - LEVELS.length),
    flashSeconds: Math.max(2, last.flashSeconds - 1)
  };
}
